curl -X POST "http://localhost:18080/api/simulate" -H "Content-Type: application/json" -d "{\"mode\":\"generated\",\"initial_capital\":10000.0,\"num_bars\":50,\"stocks\":[{\"ticker\":\"AAPL\",\"base_price\":100,\"volatility\":20,\"liquidity\":1000,\"market_cap\":5000}],\"strategy_code\":\"import netgrain\nclass Strategy:\n    def __init__(self): self.did=False\n    def on_bar(self, market, broker):\n        import netgrain as ng\n        \n        # buy once on first bar\n        \n        if self.did: return\n        broker.place_order('AAPL',10,0.0,ng.Side.BUY,ng.OrderType.MARKET)\n        self.did=True\n\"}"

curl -X POST "http://localhost:8080/api/simulate" -H "Content-Type: application/json" -d "{\"mode\":\"generated\",\"initial_capital\":10000.0,\"num_bars\":50,\"stocks\":[{\"ticker\":\"AAPL\",\"base_price\":150,\"volatility\":20,\"liquidity\":1000,\"market_cap\":5000}],\"strategy_code\":\"class Strategy:\n    def __init__(self):\n        self.last = 0\n\n    def on_bar(self, market, broker):\n        import netgrain\n        price = market['AAPL']['open']\n        if price < self.last:\n            broker.place_order(\n                'AAPL', 10, 0.0, netgrain.Side.BUY, netgrain.OrderType.MARKET\n            )\n        self.last = price\"}"

curl -X POST 'http://localhost:18080/api/simulate' -H 'Content-Type: application/json' -d '{"mode":"generated","initial_capital":10000.0,"num_bars":80,"stocks":[{"ticker":"AAPL","base_price":150,"volatility":30,"liquidity":1500,"market_cap":5000}],"strategy_code":"import netgrain\n\nclass Strategy:\n    def __init__(self):\n        self.last = 0\n        self.buys = 0\n\n    def on_bar(self, market, broker):\n        p = market[\"AAPL\"][\"open\"]\n        if self.last != 0 and (self.last - p) >= 1.0 and self.buys < 10:\n            broker.place_order(\"AAPL\", 1, 0.0, netgrain.Side.BUY, netgrain.OrderType.MARKET)\n            self.buys += 1\n        self.last = p\n"}'
